VALUES
  ('immigration-1aab856d-moex-00070', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3d2b73b6', 'sub-immigration-1aab856d-04', NULL, 'single_choice', '依司法院釋字第490號解釋，有關「中華民國男子依法皆有服兵役之義務」規定，下列敘述何者 錯誤？', '["基於憲法平等原則的要求，應將女子排除於兵役義務之外", "人民履行兵役義務的方式，應由立法者決定", "人民有服兵役之義務，此為憲法明文規定", "關於服兵役之重要事項，立法者應斟酌國家安全之需要，予以規定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00071', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3d2b73b6', 'sub-immigration-1aab856d-04', NULL, 'single_choice', '有關基本權，下列敘述何者正確？', '["依司法院釋字第748號解釋，若不許同性結婚，有違憲法增修條文消除性別歧視之規定", "秘密通訊自由屬於隱私權保障之具體態樣之一", "凡自然人均享有基本權，因此外國人亦可享有所有基本權", "國家基於對工作權之保障，有提供人民工作機會之義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00072', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3d2b73b6', 'sub-immigration-1aab856d-04', NULL, 'single_choice', '甲公司僱用女性員工，惟契約條款要求女性員工若結婚則必須辭職，關於該條款效力，下列敘述何者 錯誤？', '["結婚離職條款違反憲法上的性別平等", "結婚離職條款因屬私人間之契約，對於人民之基本權未構成限制", "結婚離職條款雖違憲，但法院應透過解釋民法條文來判斷其效力，而非直接援用憲法", "法院應認定結婚離職條款違反性別平等工作法而無效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00073', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3d2b73b6', 'sub-immigration-1aab856d-04', NULL, 'single_choice', '依司法院大法官解釋，關於正當法律程序，下列敘述何者錯誤？', '["刑事訴訟法未對律師事務所之搜索有特別之程序規定，合憲", "僅指訴訟權之程序保障，不適用於行政程序", "為保障刑事被告之防禦權，應保障被告之卷證資訊獲知權", "檢察事務官與司法警察官因調查犯罪及蒐證必要，對嫌疑人強制採尿雖有法律依據，仍因違反正當 法律程序而違憲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00074', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3d2b73b6', 'sub-immigration-1aab856d-04', NULL, 'single_choice', '依憲法、憲法增修條文及司法院大法官解釋，關於行政院之組織，下列敘述何者正確？', '["行政院與所屬各級機關之組織，均應以法律定之", "得以法律明定或授權以命令訂定行政院所屬各級機關之設置與組織", "立法者不得制定單獨組織法規範行政院所屬各級機關", "行政院與所屬各級機關之職權、設立程序及總員額，應以法律規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00075', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3d2b73b6', 'sub-immigration-1aab856d-04', NULL, 'single_choice', '有關立法委員職權之行使，下列敘述何者錯誤？', '["得聽取總統國情報告", "得提出總統、副總統彈劾案", "得提出領土變更案", "得邀請司法院院長到院備詢"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00076', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3d2b73b6', 'sub-immigration-1aab856d-04', NULL, 'single_choice', '依憲法第80條，法官須超出黨派以外，依據法律獨立審判，不受任何干涉。下列敘述何者正確？', '["法官包括檢察官", "機關釋示之行政命令，法官審判時受其拘束，應予以引用", "大法庭之裁定，對提案庭提交案件及其他類此案件，均有拘束力", "各級法院得拒絕適用違憲之行政命令"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00077', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3d2b73b6', 'sub-immigration-1aab856d-04', NULL, 'single_choice', '依憲法訴訟法之規定，關於人民聲請憲法法庭判決，下列敘述何者錯誤？', '["人民聲請標的須包含法院確定裁判", "人民聲請須於確定終局裁判送達後6個月內為之", "人民聲請判決之案件如具有憲法重要性，憲法法庭得予受理", "人民聲請判決如程序要件不合，均直接由憲法法庭作成不受理裁定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00078', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3d2b73b6', 'sub-immigration-1aab856d-04', NULL, 'single_choice', '關於地方自治團體之法律主體保障，下列敘述何者錯誤？', '["我國憲法明文保障的地方自治團體包括縣（市）以及直轄市", "鄉（鎮、市）之地方自治團體地位不是憲法保障的法律主體", "某一直轄市或縣（市）被國家廢除或裁併，該直轄市或縣（市）可主張法律主體保障而要求不受廢 除與裁併", "國家若要廢除鄉（鎮、市）地方自治團體的地位，只須修法即可為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00079', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3d2b73b6', 'sub-immigration-1aab856d-04', NULL, 'single_choice', '依司法院大法官解釋及憲法法庭判決，下列敘述何者錯誤？', '["依行政執行法對酗酒泥醉者予以管束，無須經由法院為之", "依行政執行法所為管收，應經由法院為之", "依傳染病防治法所為強制隔離處置，無須經由法院為之", "依出入國移民法所為暫時收容之處分，應經由法院為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
